"""Pipeline de visión para preprocesado, segmentación y extracción de características."""from __future__ import annotationsfrom pathlib import Pathimport numpy as npfrom federated_skin.vision.feature_extraction import extract_handcrafted_featuresfrom federated_skin.vision.preprocessing import preprocess_imagefrom federated_skin.vision.segmentation import segment_lesionclass VisionPipeline:    """    Pipeline de visión para procesar imágenes dermatoscópicas.    Este pipeline aplica, de forma secuencial:    1. preprocesado de imagen,    2. segmentación de la lesión,    3. extracción de características manuales.    Parameters    ----------    image_size : int        Tamaño cuadrado al que se redimensiona la imagen durante el        preprocesado.    """    def __init__(self, image_size: int = 224) -> None:        self.image_size = image_size    def process_image_path(self, image_path: Path) -> np.ndarray:        """        Procesa una imagen a partir de su ruta y devuelve su vector de        características.        Parameters        ----------        image_path : Path            Ruta de la imagen.        Returns        -------        np.ndarray            Vector de características extraídas.        Notes        -----        Si la segmentación no produce una región válida, se devuelve un vector        nulo para que el flujo superior pueda decidir si descartar la muestra.        """        try:            image = preprocess_image(image_path, self.image_size)            segmentation_result = segment_lesion(image)            lesion_region = segmentation_result["lesion_region"]            features = extract_handcrafted_features(                image=image,                lesion_region=lesion_region,            )            return features        except Exception:            # Se devuelve un vector nulo para mantener compatibilidad con el            # builder actual, que descarta automáticamente estas muestras.            return np.zeros(11, dtype=np.float64)